mapper.select:
SELECT cr.record_id, cr.member_id, m.member_name, cr.class_id, ct.class_name, e.employee_name AS coach_name, ct.class_begin, cr.join_time, cr.status, cr.total_sessions, cr.completed_sessions, cr.rating FROM class_record cr JOIN member m ON cr.member_id = m.member_id JOIN class_table ct ON cr.class_id = ct.class_id LEFT JOIN employee e ON ct.coach_id = e.employee_id
AND cr.class_id = #{classId}
AND ( CAST(cr.member_id AS CHAR) LIKE CONCAT('%', #{memberKeyword}, '%') OR m.member_name LIKE CONCAT('%', #{memberKeyword}, '%') )
AND cr.status = #{status}
AND cr.rating IS NULL
AND cr.rating >= #{lowRating}
AND cr.rating <= #{highRating}
ORDER BY cr.join_time DESC, cr.record_id DESC
